  ('customs-f19eb2bd-moex-00307', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '依據國際海上避碰規則對船舶燈號之定義，所謂的「拖曳燈」其燈光性能應與下列何者相同？', '["環照燈", "艉燈", "閃光燈", "桅燈"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00308', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '某航行中船舶長160英呎，依國際海上避碰規則對該類船舶之號燈規定，除應顯示舷燈與艉燈外，尚須於 桅頂或其附近之最易見處顯示環照燈二盞，上紅、下綠於一垂直線上，則該船舶最可能係屬下列何者？', '["從事拖網捕魚作業之船舶", "除拖網捕魚外，從事捕魚中之船舶", "從事引水業務之船舶", "揚帆航駛之帆船"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00309', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '航行當值之基本原則對航程計畫的要求，下列敘述何者錯誤？', '["在發航前應對所制定之任何航線予以核對", "計畫航線應清楚的顯示在適當的海圖上", "當值航行員在航程中使用計畫航線前應查證須遵行的每一航向", "航程中如決定改變計畫航線，應在實際偏離原計畫航線後儘速計畫修正航線"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00310', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '負責航行當值之航行員對羅經的定期檢查，下列敘述何者錯誤？', '["可每日測定標準羅經之誤差一次", "每次重大改變航向後，如屬可能，應測定標準羅經之誤差", "標準羅經及電羅經應經常進行比對", "電羅經複示器與主羅經同步"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00311', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '在錨泊的情況下，當值航行員確認船舶是否仍繫於原錨地之方法為下列何者？', '["利用固定航行標誌或岸上容易辨認之標的物測定方位", "利用固定航行標誌或岸上容易辨認之標的物雷達測距", "GPS定位", "ECDIS上船位監控"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00312', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '駕駛台資源管理就是：「為了達到航程中預定之安全及效率，駕駛台團隊對_____等之使用及協調」，其 中空格中的文字，下列何者正確？', '["資料、知識、經驗、技能", "物料、配件、人力、時間", "資料、知識、物料、配件", "人力、時間、經驗、技能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00313', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '為確保正常營運中船舶之航行員熟練該船的應急操舵程序，根據SOLAS公約之要求，船上每一年期間至 少應進行幾次應急操舵操演？', '["2次", "4次", "6次", "12次"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00314', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '船舶之應急信號中，下列何者為棄船緊急信號？', '["三短聲→三長聲→三短聲", "三長聲→二短聲", "七短聲→一長聲", "一長聲→四短聲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00315', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '散裝船於航行時其消防隊的組成編組中，主要負責滅火組之指揮通常係由下列何者擔任？', '["船長", "大副", "二副", "三副"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00316', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '某貨櫃船於港內錨泊時，甲板上人員突然發現船艏處之儲藏室失火，則當值航行員在駕駛台接到通知後， 應立即以汽笛或警鈴鳴放下列何信號，以緊急通報全船人員發生火警？', '["一長聲一短聲，且至少連續6秒鐘", "一短聲一長聲，且至少連續6秒鐘", "一短聲一長聲，且至少連續10秒鐘", "一長聲一短聲，且至少連續10秒鐘"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "66336841947a", "answer_pdf_sha1": "bcdd50686399", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "2005", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
